1570		if info.IsDir() {
1571			return nil
1572		}
1573	
1574		out, err := internalgit.Command(context.Background(), projectRoot, "rev-parse", "--is-inside-work-tree").Output()
1575		if err != nil || strings.TrimSpace(string(out)) != "true" {
1576			return nil
